const Q_CHEMISTRY_2004=[{"id": "objective>Chemistry>2004>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolysis of brine, the anode is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zinc      </div>", "<div style=\"font-family:Cambria;font-size:17px;\">platinum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolysis of brine (NaCl), the cathode used is platinum or graphite and the anode used is graphite (a form of carbon). This is because of the inert nature of the carbon so as to protect it from being oxidized. </div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2004>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ↔ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  In the endothermic reaction above, more product formation will be favoured by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in pressure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in volume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a constant volume</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> ⇔ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>.  <br/>  According to Lechatelier principle, a decrease in pressure usually favors the side with the higher number of mole of gaseous molecules and vice versa. </div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2004>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state of chlorine in HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">–1    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">–5    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+7    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/>  <br/>  HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is a compound  <br/>  <br/>  The oxidation number of a compound is zero  <br/>  <br/>  HClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = O  O.N → Oxidation number  <br/> O.N(H) = +1  <br/>  <br/>  O.N(Cl)= X  <br/>  <br/>  O.N(O) = -2  <br/>  <br/> 1 + x + 4(-2) = 0 <br/>  <br/>  1 + x - 8 = 0 <br/> x = +7 </div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2004>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following hydrogen halides has the highest entropy value?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HBr    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HF    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HI    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">HI has the highest entropy value because it is the heaviest and largest molecule among the hydrogen halides, leading to more possible ways(microstates) the molecules can be arranged and moved.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2004>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of silver deposited when a current of 10A is passed through a solution of silver salt for 4830s is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">54.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">27.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.5g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">108.0g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>⇔ Ag.  <br/> I mole of Ag = 108g.    1e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> = 96500C  <br/> Q= It = 10 x 4830C = 48300C  <br/> 96,500C  yields 108g of Ag   <br/>  <br/> 48300C yields x   <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">48300x108<hr size=\"1\" />96500</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">54g</td></tr></table></div></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2004>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following acts as both a reducing and an oxidizing agent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An oxidizing agent is a substance that has the ability to oxidize other substances, meaning it causes them to lose electrons. A reducing agent, on the other hand, reduces other substances by donating electrons to them. SO2 can act as both an oxidizing and reducing agent because it can either gain or lose electrons depending on the reaction it is involved in. </div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2004>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following shows little or no net reaction when the volume of the system is decreased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> ⇔ 3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇔ 2HI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇔ N2O4(g)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5(g)</span>⇔ PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the number of moles of the gaseous reactant balances that of the product, volume change or pressure change has no effect.   </div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2004>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/> Given that ΔH [CO] is  –110.4kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>and ΔH  [CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]  is  –393.0kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>,  the  energy change for the reaction above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">–565.2kJ    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+503.4kJ </div>", "<div style=\"font-family:Cambria;font-size:17px;\">–503.4kJ    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+282.6kJ</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>\t→  2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/> H=∑H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">pr</span> - ∑H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rx</span>   = 2(-393) - 2(-110.4)  <br/> =-786+220.8 <br/> = -565.2Jmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  </div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2004>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">ZnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> heat<span style=\"position:relative;left:-20px;top:12px;\">&#8594</span>  Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  <br/> In the reaction above, zinc has been</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">displaced    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decomposed</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, ZnO is reduced to Zn by the removal of oxygen. Reduction is the process of gaining electrons or losing oxygen. Hence, the correct answer is option 3.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2004>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of gas is evolved at s.t.p. if 2g of calcium trioxocarbonate(IV)  is added to a solution of hydrochloric acid?  <br/> [Ca = 40, C = 12, O = 16, Cl = 35.5,H = 1, Molar volume of a gas at s.t.p = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">224cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">112cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2240cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">448cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2HCl + CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/> From the equation above: <br/> 100g (1 mole) of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> produces 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> (1 mole) of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 100g → 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> 2g → x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">50<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">22.4<hr size=\"1\" />x</td></tr></table></div> <br/> 50x = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">22.4<hr size=\"1\" />50</td><td style=\"text-align:center;\">dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td></tr></table></div> <br/> x = 0.448dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 448cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2004>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A chemical reaction is always associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a change in the  nature of the reactants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the formation of new substances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a change in the volume of the reactants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the composition of one of the substances</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A chemical reaction is always associated with the formation of new substances. This is because a chemical reaction involves the breaking of bonds in the reactants and the formation of new bonds to create new substances, which are the products.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2004>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a solid substance disappears completely as a gas on heating, the substance is said to have undergone</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sublimation    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a solid substance disappears completely as a gas on heating, the substance is said to have undergone sublimation. Sublimation is the process by which a substance changes from a solid to a gas without first becoming a liquid.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2004>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a solution contains 4.9g of tetraoxosulphate(VI) acid, calculate the amount of copper(II) oxide that will react with it  <br/> [Cu = 64, O = 16, S = 32, H = 1]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">80.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.8g  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is the equation of the reaction: <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + CuO  → CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O.  <br/> According to the equation <br/> 98g (1 mole) H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> reacts with 80g (1 mole) CuO <br/> 4.9g of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will react with x of CuO <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">98<hr size=\"1\" />4.9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />x</td></tr></table></div> <br/> 20x = 80 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80<hr size=\"1\" />20</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4.00g</td></tr></table></div> <br/> </div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2004>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Vulcanization involves the removal of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the single bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the double bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a polymer      </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monomer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vulcanization is a chemical process by which rubber is heated with sulfur at high temperatures to improve its properties. During this process, the double bonds in the rubber molecule are broken and sulfur atoms are inserted between the carbon chains to form cross-links. Therefore, vulcanization involves the removal of the double bond.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2004>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The alkyl group can be represented by the general formula</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n</span>      </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n – 2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 1</span>    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is represented by the general formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 1</span>. This formula represents a group of carbon and hydrogen atoms, where 'n' is the number of carbon atoms. The number of hydrogen atoms is always twice the number of carbon atoms plus one. Alkyl groups are formed from the loss of a hydrogen atom from an alkane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2004>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">conc H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></span>→<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">180°C</span>  Y  <br/> In the reaction above, Y represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>COOH      </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>OCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>     </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction given is a dehydration reaction of ethanol (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH) in the presence of a strong acid catalyst (concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) and heat. The product of this reaction is ethene (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>), a hydrocarbon with a double bond.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2004>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the production of soap, concentrated sodium chloride solution is added to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">saponify the soap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">emulsify the soap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the solubility of the soap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the solubility of the soap</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the production of soap, concentrated sodium chloride solution is added to decrease the solubility of the soap. This process is known as 'salting out'. It helps to separate the soap from the aqueous solution, allowing it to precipitate and be collected.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2004>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oxyacetylene flame is used for iron welding because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">evolves a lot of heat when burnt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissociates to produce carbon(IV)oxide and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">makes  the  iron  metal  solidify  very quickly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combines with oxygen to give a pop sound.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oxyacetylene flame is used for iron welding because it evolves a lot of heat when burnt. The high temperature produced by the combustion of acetylene with oxygen (oxyacetylene flame) is sufficient to melt iron and other metals, making it ideal for welding purposes.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2004>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these reagents can confirm the presence of a triple bond?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bromine gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bromine water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Acidified KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Copper(I) Chloride</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammoniacal copper (1) chloride is used to distinguish, Alkynes (≡) from alkenes( = )  <br/>  <br/> Bromine water will decolorize alkene and alkyne because they are unsaturated. Copper (I) chloride is a more specific test for alkynes because it is a test for triple bonds <br/>  <br/>  <br/> Bromine water helps to differentiate saturated and unsaturated compounds. It gets decolourised when reacted with unsaturated compounds. But CuCl and AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is a more specific test to differentiate between alkenes and alkynes. It forms metallic derivatives with alkynes</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2004>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The IUPAC nomenclature of the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3,4-dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,3-dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-ethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-ethylpentane</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2, 3-dimethyl hexane. <br/> the bond that we have throughout is a single bond, hence the root name ends in -ane. <br/> the longest continuous carbon chain is 6, so the root name is hexane. <br/> counting from left to right, we have methyl on the second and third carbons, hence 2,3-dimethyl. </div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2004>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An isomer of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-ethylbutane    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">butane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbutane  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpropane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An isomer of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span> is 2-methylbutane. Isomers are compounds with the same molecular formula but different structural formulas. 2-methylbutane is an isomer of pentane (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>) because it has the same number of carbon and hydrogen atoms but arranged differently.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2004>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanol + Alkanoic acid → Ester + Water  <br/> The reverse reaction of the equation above is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">saponification    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydration</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reverse reaction of esterification is hydrolysis. In chemistry, hydrolysis is a reaction in which a compound is split into other compounds by reacting with water. In this case, an ester reacts with water to form an alkanol and an alkanoic acid.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2004>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>(g) + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/> The reaction above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">acidification    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">esterification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decarboxylation    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carboxylation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> is a decarboxylation reaction. Decarboxylation is a chemical reaction that removes a carboxyl group and releases carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). In this reaction, the carboxyl group of acetic acid (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH) is removed, forming methane (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>) and carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>).</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2004>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic of the alkane family is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">substitution reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutralization reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">addition reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elimination reaction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic of the alkane family is that they undergo substitution reactions. Alkanes are saturated hydrocarbons, meaning they have single bonds only. They are relatively unreactive, but can undergo substitution reactions where a hydrogen atom is replaced by another atom or group of atoms.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2004>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pollution of underground water by metal ions is very likely in a soil that has high</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkalinity    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrate content </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidity    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloride content</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pollution of underground water by metal ions is very likely in a soil that has high acidity. Acidic soils can leach metal ions into the groundwater. This is because many metals are more soluble in acidic conditions, so they can be washed out of the soil and into the water.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOIL POLLUTION"}, {"id": "objective>Chemistry>2004>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility in  mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of 20<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> of CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> dissolved in 100<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">g</span> of water  at 180<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.13    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(number of moles of solute) <hr size=\"1\" /> (volume of solution )</td><td style=\"text-align:center;\"> </td><td style=\"text-align:center;\">number of moles of solute</td><td style=\"text-align:center;\"> =</td><td style=\"text-align:center;\">20<hr size=\"1\" />160</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.125</td></tr></table></div> <br/> Mass of water = 100g <br/> N.B: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Density</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />volume</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> Density of water = 1gcm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> Volume of 100g of water = 100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 0.1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Assume that the volume of water is the volume of the solution <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">0.125<hr size=\"1\" />0.1</td><td style=\"text-align:center;\"></td></tr></table></div></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.25</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <br/> </div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2004>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these compounds is a normal salt?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>     </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHS</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is the only normal salt within group because it does not contain H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>.  This is simply because it is formed by the complete replacement of the hydrogen in the parent acid by Sodium. It is formed when all the replaceable hydrogen in an acid is completely replaced by metallic or ammonium ions.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2004>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A carcinogenic substance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen(II)oxide  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(II)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">asbestos dust  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sawdust</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A carcinogenic substance is a substance that can cause cancer in living tissues. Asbestos dust is a well-known carcinogen. The other options (nitrogen(II)oxide, carbon(II)oxide, and sawdust) are not typically considered carcinogens.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2004>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of 0.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will exactly neutralize 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> of 0.1moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.3cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2NaOH   →  Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  =  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td></tr></table></div> </td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">(0.5xV<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>)<hr size=\"1\" />(0.1x20)</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">½</td></tr></table></div></td></tr></table></div>   <br/>  ∴ VA = 0.1 x 20 = 2cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. </div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2004>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium Tetraoxosulphate(VI)  dissolves in water only sparingly to form a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">colloid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">suspension </div>", "<div style=\"font-family:Cambria;font-size:17px;\">precipitate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium tetraoxosulphate (VI) is only slightly soluble and comes out as a white precipitate. This is because the bulk of salt does not dissolve but remain suspended in water. </div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>2004>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hardness of water is caused by the presence of the ions of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium and magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium and sodium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium and silver</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium and potassium</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hardness of water is primarily caused by the presence of calcium and magnesium ions. These ions in water can cause a variety of problems, including scale formation on pipes and appliances, soap scum in bathrooms, and reduced effectiveness of soaps and detergents.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2004>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">It is difficult to achieve an orderly arrangement of the molecules of a gas because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can collide  with  one  another  in  the container </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are too small in size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have little force of attraction between them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have no definite shape</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The molecules of a gas are difficult to arrange in an orderly manner because they have little force of attraction between them. This is due to the fact that gas molecules are far apart from each other and move freely, making it difficult to maintain an orderly arrangement.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2004>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the s-orbital is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elliptical    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">spiral </div>", "<div style=\"font-family:Cambria;font-size:17px;\">circular    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">spherical</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the s-orbital is spherical. In quantum mechanics, the s-orbital is the basic orbital, with a spherical shape. It is centered around the nucleus of the atom.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2004>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following mixtures of gases is likely to burn in flame?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Helium and neon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neon and nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neon and hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen and helium</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mixture of Neon and Hydrogen is likely to burn in flame. This is because Hydrogen is a highly flammable gas and can easily ignite when mixed with an oxidizer. Neon is an inert noble gas and does not participate in chemical reactions, including oxidation. The reason is that hydrogen is a highly flammable gas that can ignite and burn in the presence of oxygen or other oxidizing agents. </div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2004>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The property of chlorine which causes hydrogen chloride to be more ionic than the chlorine molecule is its.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electronegativity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electropositivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electron affinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrovalency</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The property of chlorine which causes hydrogen chloride to be more ionic than the chlorine molecule is its electronegativity. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. Chlorine has a higher electronegativity than hydrogen, which causes the bond in HCl to be polar, and thus more ionic.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2004>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the experiment above, X is a mixture of nitrogen, carbon(IV) oxide and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inert gas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impurities</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air which is composed chiefly of Nitrogen, carbon (IV) oxide, oxygen and inert gas. The sample has been treated with alkaline pyrogallol which is a drying agent for oxygen. The remaining components will be \"Nitrogen, carbon (IV) oxide, and inert gases.\"</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2004>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A given volume of methane diffuses in 20s.How long will it take the same volume  of sulphur(IV)oxide  to  diffuse under the same conditions?  <br/> [C = 12, H = 1, S = 32, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40s    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">60s    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20s    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5s</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Relative molecular mass of CH4  <br/> = (1 × 12) + (4 × 1)  <br/> = 12 + 4  <br/> = 16 <br/> Relative molecular mass of SO2  <br/> = (1 × 32) + (2 × 16)  <br/> = 32 + 32  <br/> = 64 <br/> tSO2/tCH4 = √MSO2/MCH4 <br/> t/20 = √64/16  <br/> t/20 = √4 <br/> t/20 = 2 <br/> ∴ t = 20 * 2 = 40sec</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2004>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine consisting of two isotopes of mass numbers 35 and 37 in the ratio 3 : 1 has an atomic mass of 35.5. Calculate the relative abundance of the isotope of mass number 37.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">20    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">75    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">35.5=35x + 37(100-x)/100 <br/> 3550=35x + 3700 - 37x <br/> 3550-3700 = 35x - 37x <br/> -150= -2x <br/> x=75% <br/> Relative abundance 0f 37 = 100 - 75 =25%</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2004>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An electron can be  added to a halogen atom to form a halide ion with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8 valence electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 valence electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 valence electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 valence electrons.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Halogen atoms are in Group 7 of the periodic table and have 7 valence electrons. When an electron is added to a halogen atom, it forms a halide ion with 8 valence electrons, achieving a stable electron configuration.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2004>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> What is the value of x in the nuclear reaction above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">226    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">220    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">227    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">222</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">226</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">88</span>Ra  → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">86</span>Rn + ∝ - particle  <br/>  <br/>  ∝ - particle = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He <br/>  <br/>  <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">226</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">88</span>Ra  → <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">86</span> Rn + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>He <br/>  <br/>  To balance up the mass numbers  <br/> 226 = x + 4; x = 222  <br/>  <br/>  To balance up the atomic numbers, 88 = 86+2 = Balanced.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2004>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Charles' law, the volume of a gas becomes zero at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">–100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">–273<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">–373<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Charles' law, the volume of a gas is directly proportional to its temperature in Kelvin. This implies that the volume of a gas becomes zero at absolute zero, which is -273 degrees Celsius.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2004>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When steam is passed over red-hot carbon, the substances produced are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen and carbon(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen and carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen and trioxocarbonate(IV)  <br/> acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen, oxygen and carbon(IV) oxide.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When steam (water vapor) is passed over red-hot carbon, the reaction produces hydrogen and carbon(II) oxide (also known as carbon monoxide). This is a type of reduction reaction where water is reduced by carbon.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2004>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium Hydroxide is used in the dyeing industry as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dye</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mordant</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium Hydroxide is used as a mordant in the dyeing industry. A mordant is a substance used to set dyes on fabrics by forming a coordination complex with the dye, which then attaches to the fabric. It may be used for dyeing fabrics, or for intensifying stains in cell or tissue preparations.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2004>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Transition metals possess variable oxidation states because they have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrons in the s orbitals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrons in the d orbitals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partially filled p orbitals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a variable number of electrons in the p orbitals. </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transition metals possess variable oxidation states because they have electrons in the d orbitals. The d orbitals are able to accommodate a variable number of electrons, allowing transition metals to form multiple oxidation states.</div>", "topic": "METALS AND THEIR COMPOUNDS : METALS OF THE FIRST TRANSITION SERIES"}, {"id": "objective>Chemistry>2004>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The allotrope of carbon used in the decolourization of sugar is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lampblack </div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charcoal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The allotrope of carbon used in the decolourization of sugar is charcoal. Charcoal has a porous structure that can absorb impurities such as colorants from substances, making it useful for decolorizing sugar.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2004>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon is tetravalent because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the 2s and 2p atomic orbitals hybridize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all the atomic  orbitals  of  carbon hybridize</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the electrons in all the orbitals of carbon are equivalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the electrons in both the 2s and 2p orbitals are equivalent.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon is tetravalent because the 2s and 2p atomic orbitals hybridize. Hybridization is a process of atomic orbital mixing in quantum mechanics. In carbon, the 2s and three 2p orbitals hybridize to form four sp3 hybrid orbitals, each of which can form a covalent bond, making carbon tetravalent.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2004>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium metal is always kept under oil because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is reduced by atmospheric nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">readily reacts with water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reacts  with  oxygen  and  carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reacts vigorously on exposure to air</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium metal is always kept under oil because of its reactivity on exposure to air. </div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2004>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alloys are best prepared by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cooling a molten mixture of the metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing a mixture of their metallic oxides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arc-welding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electroplating</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alloys are best prepared by cooling a molten mixture of the metals. This process is known as alloying. The metals are first melted together and then cooled to form a solid mixture. This process ensures that the metals are thoroughly mixed together.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2004>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (IV) oxide bleaches by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorption</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(iv)oxide bleaches by reduction while chlorine bleaches by oxidation.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2004>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases can be collected by the method of downward delivery?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine gas can be collected by the method of downward delivery. This is because chlorine is denser than air. The method of downward delivery, also known as downward displacement of air, is used for gases that are denser than air.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}];
